{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = exp(d_I[ei] / 255.0f);
    }
}

__kernel void prepare_kernel(long d_Ne,
                             __global float *d_I,
                             __global float *d_sums,
                             __global float *d_sums2)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        float v = d_I[ei];
        d_sums[ei] = v;
        d_sums2[ei] = v * v;
    }
}

__kernel void reduce_kernel(long d_Ne,
                            long d_no,
                            int d_mul,
                            __global float *d_sums,
                            __global float *d_sums2,
                            int blocks2_work_size)
{
    size_t tx = get_local_id(0);
    size_t bx = get_group_id(0);
    size_t lsize = get_local_size(0);

    if (tx == 0) {
        long start = (long)bx * (long)lsize;
        if (start < d_no) {
            long end = start + (long)lsize;
            if (end > d_no) end = d_no;

            float sum = 0.0f;
            float sum2 = 0.0f;
            for (long idx = start; idx < end; ++idx) {
                long pos = idx * (long)d_mul;
                sum += d_sums[pos];
                sum2 += d_sums2[pos];
            }

            long out = (long)bx * (long)d_mul * (long)lsize;
            d_sums[out] = sum;
            d_sums2[out] = sum2;
        }
    }
}

__kernel void srad_kernel(float lambda,
                          int Nr,
                          int Nc,
                          long Ne,
                          __global int *iN,
                          __global int *iS,
                          __global int *jE,
                          __global int *jW,
                          __global float *d_dN,
                          __global float *d_dS,
                          __global float *d_dW,
                          __global float *d_dE,
                          float q0sqr,
                          __global float *d_c,
                          __global float *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int i = (int)(ei / (long)Nc);
        int j = (int)(ei - (long)i * (long)Nc);

        float Jc = d_I[ei];

        float dN = d_I[(long)iN[i] * (long)Nc + (long)j] - Jc;
        float dS = d_I[(long)iS[i] * (long)Nc + (long)j] - Jc;
        float dW = d_I[(long)i * (long)Nc + (long)jW[j]] - Jc;
        float dE = d_I[(long)i * (long)Nc + (long)jE[j]] - Jc;

        d_dN[ei] = dN;
        d_dS[ei] = dS;
        d_dW[ei] = dW;
        d_dE[ei] = dE;

        float G2 = (dN * dN + dS * dS + dW * dW + dE * dE) / (Jc * Jc);
        float L = (dN + dS + dW + dE) / Jc;

        float num = 0.5f * G2 - 0.0625f * (L * L);
        float den = 1.0f + 0.25f * L;
        float qsqr = num / (den * den);

        den = (qsqr - q0sqr) / (q0sqr * (1.0f + q0sqr));
        float c = 1.0f / (1.0f + den);

        if (c < 0.0f) c = 0.0f;
        else if (c > 1.0f) c = 1.0f;

        d_c[ei] = c;
    }
}

__kernel void srad2_kernel(float lambda,
                           int Nr,
                           int Nc,
                           long Ne,
                           __global int *iN,
                           __global int *iS,
                           __global int *jE,
                           __global int *jW,
                           __global float *d_dN,
                           __global float *d_dS,
                           __global float *d_dW,
                           __global float *d_dE,
                           __global float *d_c,
                           __global float *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < Ne) {
        int i = (int)(ei / (long)Nc);
        int j = (int)(ei - (long)i * (long)Nc);

        float cN = d_c[ei];
        float cS = d_c[(long)iS[i] * (long)Nc + (long)j];
        float cW = d_c[ei];
        float cE = d_c[(long)i * (long)Nc + (long)jE[j]];

        float D = cN * d_dN[ei] + cS * d_dS[ei] + cW * d_dW[ei] + cE * d_dE[ei];
        d_I[ei] = d_I[ei] + 0.25f * lambda * D;
    }
}

__kernel void compress_kernel(long d_Ne,
                              __global float *d_I)
{
    long ei = (long)get_global_id(0);
    if (ei < d_Ne) {
        d_I[ei] = log(d_I[ei]) * 255.0f;
    }
